#include <stdio.h>
#include <stdlib.h>

int v2(int x){
    int cnt = 0;
    while ((x & 1) == 0){
        x >>= 1;
        cnt++;
    }
    return cnt;
}

int cmp(const void *a, const void *b){
    return *(int*)a - *(int*)b;
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        int total = 2*N;
        int evenCount = 0;
        int *costs = (int*)malloc(total * sizeof(int));
        int costSize = 0;
        for(int i=0;i<total;i++){
            int a; scanf("%d", &a);
            if(a % 2 == 0){
                evenCount++;
                costs[costSize++] = v2(a);
            }
        }
        if(evenCount == N){
            printf("0\n");
        }else if(evenCount < N){
            printf("%d\n", N - evenCount);
        }else{
            int need = evenCount - N;
            qsort(costs, costSize, sizeof(int), cmp);
            long long ans = 0;
            for(int i=0;i<need;i++) ans += costs[i];
            printf("%lld\n", ans);
        }
        free(costs);
    }
    return 0;
}

