import java.io.*;
import java.util.*;
public class Main {
    private static int v2(long x){
        int cnt=0;
        while((x & 1L) == 0){
            x >>= 1;
            cnt++;
        }
        return cnt;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st;
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder sb = new StringBuilder();
        while(T-- > 0){
            int N = Integer.parseInt(br.readLine().trim());
            int total = 2 * N;
            st = new StringTokenizer(br.readLine());
            int evenCnt = 0;
            int[] costs = new int[total];
            int idx = 0;
            for(int i=0;i<total;i++){
                long a = Long.parseLong(st.nextToken());
                if((a & 1L) == 0){
                    evenCnt++;
                    costs[idx++] = v2(a);
                }
            }
            if(evenCnt == N){
                sb.append(0).append('\n');
            } else if(evenCnt < N){
                sb.append(N - evenCnt).append('\n');
            } else {
                int need = evenCnt - N;
                Arrays.sort(costs, 0, idx);
                long ans = 0;
                for(int i=0;i<need;i++) ans += costs[i];
                sb.append(ans).append('\n');
            }
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
import sys

def v2(x: int) -> int:
    cnt = 0
    while x % 2 == 0:
        x //= 2
        cnt += 1
    return cnt

def solve():
    data = list(map(int, sys.stdin.read().split()))
    it = iter(data)
    T = next(it)
    out_lines = []
    for _ in range(T):
        N = next(it)
        total = 2 * N
        even_cnt = 0
        costs = []
        for _ in range(total):
            a = next(it)
            if a % 2 == 0:
                even_cnt += 1
                costs.append(v2(a))
        if even_cnt == N:
            out_lines.append('0')
        elif even_cnt < N:
            out_lines.append(str(N - even_cnt))
        else:
            need = even_cnt - N
            costs.sort()
            out_lines.append(str(sum(costs[:need])))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

